1	`timescale 1ns / 1ns
2	`include "constants.vams"
3	
4	module cic_multichannel_tb;
5	
6	   // Configurable parameters
7	   parameter n_chan = 12;
8	
9	   // Testbench stimulus
10	   localparam ADC_DWI = 16;
11	   localparam MULT_GUARD_BITS = 3; // Guard bits to keep in output of mixer
12	   localparam OSC_WIDTH = 18; // Width of local oscillator
13	
14	   localparam CLK_PERIOD = 10;
15	   localparam CLK_SLOW_RATIO = 2; // TODO: Make this programmable
16	   localparam CLK_PER_SLOW = CLK_PERIOD*CLK_SLOW_RATIO;
17	
18	   integer den, logden;
19	   reg [2:0] shift;
20	   real fden, fnum, ampi, ampo_expect, phsi, phs_marg;
21	   reg overload=0;
22	
23	   integer num_tx=0;
24	
25	   initial begin
26	      // Test not designed to work with phsi near pi
27	      // 4 <= den <= 128, no factor of fnum
28	      if (!$value$plusargs("amp=%f", ampi)) ampi=10000.0;
29	      if (!$value$plusargs("phs=%f", phsi)) phsi=0.0;
30	      if (!$value$plusargs("den=%d", den )) den=16;
31	      ampo_expect=ampi;
32	      phs_marg=0.00002;
33	      phs_marg=0.95/ampi;
34	      if (ampi > 32765.0) begin
35	         overload=1;
36	         ampo_expect=32764.0;
37	         phs_marg=0.2;
38	      end
39	      $display("ampi=%.2f  ampo_expect=%.2f  phsi=%.5f  phs_marg=%.5f",
40	               ampi, ampo_expect, phsi, phs_marg);
41	      fden=den;
42	      fnum=3.0;
43	      logden=$clog2(den);
44	      shift=logden-2;
45	      $display("den=%d  logden=%d  shift=%d", den, logden, shift);
46	   end
47	
48	   reg clk, slow_clk;
49	   integer cc, errors;
50	
51	   initial begin
52	      if ($test$plusargs("vcd")) begin
53	         $dumpfile("cic_multichannel.vcd");
54	         $dumpvars(5,cic_multichannel_tb);
55	      end
56	      errors=0;
57	      $display("    X1      Y1      X2      Y2     R1    OK   Phi1  OK");
58	      for (cc=0; cc<64*den; cc=cc+1) begin
59	         clk=0; #(CLK_PERIOD/2);
60	         clk=1; #(CLK_PERIOD/2);
61	      end
62	
63	      if (num_tx == 0) begin
64	         $display("ERROR: No transactions, nothing was tested.");
65	         errors = errors + 1;
66	      end
67	      if (errors == 0) begin
68	        $display("PASS");
69	        $finish(0);
70	      end else begin
71	        $display("FAIL");
72	        $stop(0);
73	      end
74	   end
75	
76	   integer cc_s;
77	
78	   initial begin
79	      for (cc_s=0; cc_s <64*den*CLK_SLOW_RATIO; cc_s = cc_s + 1) begin
80	         slow_clk=0; #(CLK_PER_SLOW/2);
81	         slow_clk=1; #(CLK_PER_SLOW/2);
82	      end
83	   end
84	
85	   // ---------------------
86	   // Generate stimulus
87	   // ---------------------
88	
89	   reg signed [ADC_DWI-1:0] adc=0;
90	   integer noise;
91	   integer nseed=1234;
92	
93	   integer ccmod;
94	   real th0, tha, thb;
95	   reg signed [OSC_WIDTH-1:0]  cosa=0, sina=0, cosb=0, sinb=0;
96	   reg signed [OSC_WIDTH-1:0] xcosa,  xsina,  xcosb,  xsinb;
97	   integer ax;  // can be huge in the face of clipping.  Don't be stupid and
98	           // set amplitude larger than 2^31 in ADC sine wave below.
99	           // 100 X overdrive is plenty for this purpose.
100	   reg sample=0;
101	
102	   reg stb_in=0;
103	
104	   // Generate stimulus at half rate to test strobe capability
105	   // Stimulus code based on mon_12_tb.v
106	   // TODO: Make this configurable
107	   always @(posedge clk) begin
108	      stb_in <= ~stb_in;
109	   end
110	   always @(posedge slow_clk) begin
111	      noise = $dist_normal(nseed,0,1024);
112	      th0 = (cc_s)*`M_TWO_PI*fnum/fden - phsi;
113	      ax = $floor(ampi*$cos(th0)+0.5+noise/1024.0);
114	      if (ax >  32767) ax =  32767;
115	      if (ax < -32678) ax = -32768;
116	      adc <= ax;
117	      // $display("%d adc", adc);
118	      ccmod = cc_s%den;
119	      tha = ccmod*`M_TWO_PI*fnum/fden;
120	      // Scaling of LO is non-obvious.  Set such that a square-wave input
121	      // can't overflow CIC.  Conceptually that's pi/2, so set to pi/4 of full
122	      // scale and absorb a factor of two later.
123	      // 2^17 = 131072 - a little bit to cover rounding
124	      xcosa = $floor(131070.0*$cos(tha)+0.5);  cosa <= xcosa;
125	      xsina = $floor(131070.0*$sin(tha)+0.5);  sina <= xsina;
126	      thb = ccmod*`M_TWO_PI*7.0/fden;
127	      xcosb = $floor(13107.00*$cos(tha)+0.5);  cosb <= xcosb;
128	      xsinb = $floor(13107.00*$sin(tha)+0.5);  sinb <= xsinb;
129	      sample <= ccmod==0;
130	   end
131	
132	   // ---------------------
133	   // Instantiate Mixers
134	   // ---------------------
135	
136	   wire signed [ADC_DWI+MULT_GUARD_BITS-1:0] adc_a_cos, adc_a_sin, adc_b_cos, adc_b_sin;
137	
138	   mixer #(
139	      .dwi(ADC_DWI),
140	      .davr(MULT_GUARD_BITS),
141	      .dwlo(OSC_WIDTH))
142	   i_mixer_a_cos (
143	      .clk(slow_clk),
144	      .adcf(adc),
145	      .mult(cosa),
146	      .mixout(adc_a_cos)
147	   );
148	
149	   mixer #(
150	      .dwi(ADC_DWI),
151	      .davr(MULT_GUARD_BITS),
152	      .dwlo(OSC_WIDTH))
153	   i_mixer_a_sin (
154	      .clk(slow_clk),
155	      .adcf(adc),
156	      .mult(sina),
157	      .mixout(adc_a_sin)
158	   );
159	
160	   // ---------------------
161	   // Instantiate Sampler
162	   // ---------------------
163	   wire cic_sample, cc_sample;
164	
165	   multi_sampler #(
166	      .sample_period_wi(8),
167	      .dsample0_en(1),
168	      .dsample0_wi(8),
169	      .dsample1_en(0),
170	      .dsample1_wi(8),
171	      .dsample2_en(0),
172	      .dsample2_wi(8))
173	   i_multi_sampler (
174	      .clk(clk),
175	      .reset(1'b0),
176	      .ext_trig(1'b1),
177	      .sample_period({den[6:0],1'b0}),
178	      .dsample0_period(8'h1),
179	      .dsample1_period(8'h1),
180	      .dsample2_period(8'h1),
181	      .sample_out(cic_sample),
182	      .dsample0_stb(cc_sample),
183	      .dsample1_stb(), // Unused output
184	      .dsample2_stb()  // Unused output
185	   );
186	
187	   // ---------------------
188	   // Instantiate DUT
189	   // ---------------------
190	
191	   wire sr_val;
192	   wire [19:0] sr_out;
193	   wire [n_chan*(ADC_DWI+MULT_GUARD_BITS)-1:0] d_in_flat;
194	
195	   wire di_stb_out;
196	   wire [31:0] di_sr_out;
197	
198	   assign d_in_flat = {{(n_chan-4)*(ADC_DWI+MULT_GUARD_BITS){1'b0}},
199	                       adc_a_sin,
200	                       adc_a_cos,
201	                       adc_a_sin,
202	                       adc_a_cos};
203	
204	   cic_multichannel #(
205	      .n_chan        (n_chan),
206	
207	      // DI parameters
208	      .di_dwi        (ADC_DWI+MULT_GUARD_BITS),  // data width
209	      .di_rwi        (32),  // result width
210	                            // Difference between above two widths should be N*log2 of the maximum number
211	                            // of samples per CIC sample, where N=2 is the order of the CIC filter.
212	
213	      .di_noise_bits (1),   // NOTE: Setting to 1 to compensate for removed /2 from double_inte
214	      .cc_outw       (20),  // CCFilt output width; Must be 20 if using half-band filter
215	      .cc_halfband   (1),
216	      .cc_use_delay  (0),   // Match pipeline length of filt_halfband=1
217	      .cc_shift_base (0))   // Bits to discard from previous acc step
218	   dut
219	   (
220	      .clk           (clk),
221	      .reset         (1'b0),
222	      .stb_in        (stb_in),
223	      .d_in          (d_in_flat),    // Flattened array of unprocessed data streams. CH0 in LSBs
224	      .cic_sample    (cic_sample),
225	
226	      .cc_sample     (cc_sample),
227	      .cc_shift      ({shift,1'b1}), // controls scaling of filter result
228	
229	      .di_stb_out    (di_stb_out),   // TODO: Test Double Integrator tap
230	      .di_sr_out     (di_sr_out),
231	
232	      .cc_stb_out    (sr_val),
233	      .cc_sr_out     (sr_out)
234	   );
235	
236	
237	   reg strobe1=0;
238	   integer col=0;
239	   reg signed [19:0] out_set[0:n_chan-1];
240	
241	   always @(posedge clk) begin
242	      strobe1 <= sr_val;
243	      if (sr_val) begin
244	         col <= (col==n_chan-1) ? 0 : col+1;
245	         out_set[col] <= sr_out;
246	         // $display("%d: out[%d] <= %d", cc, col, result);
247	      end
248	   end
249	
250	   real xr, xi, ampo, phso;
251	   reg amp_pass, phs_pass, fault, use_row;
252	
253	   always @(negedge clk) if (cc_s/den > 18) begin
254	      //if (strobe & ~strobe1) $display("#");
255	      //if (strobe) $display("%d", result);
256	      xr=out_set[0];
257	      xi=out_set[1];
258	      ampo=$sqrt(xr*xr+xi*xi)/(fden*fden)*(1<<(2*shift));
259	      ampo=ampo*131072.0/131070.0;
260	      phso=$atan2(xi,xr);
261	      amp_pass = overload ? ampo > ampo_expect :
262	                 ((ampo > ampo_expect*0.99995-0.7) & (ampo < ampo_expect*1.00005+0.7));
263	      phs_pass = (phso>phsi-phs_marg) & (phso<phsi+phs_marg);
264	
265	      if (sr_val && (col==0)) begin
266	         num_tx <= num_tx + 1;
267	         $display("%d %d %d %d  %8.2f %b %8.5f %b %s.",
268	                  out_set[0], out_set[1], out_set[2], out_set[3],
269	                  ampo, amp_pass, phso, phs_pass, fault ? "FAULT" : "");
270	         fault = (~amp_pass | ~phs_pass);
271	         if (fault) errors=errors+1;
272	      end
273	   end
274	
275	endmodule
