`timescale 1ns / 1ns

module half_filt_tb;

parameter len=10;
parameter per=28;

reg clk;
integer cc;
initial begin
	if ($test$plusargs("vcd")) begin
		$dumpfile("half_filt.vcd");
		$dumpvars(5,half_filt_tb);
	end
	for (cc=0; cc<per*500; cc=cc+1) begin
		clk=0; #5;
		clk=1; #5;
	end
	$finish(0);
end

reg signed [19:0] ind=0, ind0=0;
reg ing=0;
integer noise;
integer nseed=1234;

always @(posedge clk) begin
	// ind <= (cc%16==0) ? ((cc>150) ? -400000 : 0) : 20'bx;
	ind <= 20'bx;
	if (cc%per==0) begin
		noise = $dist_normal(nseed,0,1024);
		ind0 = $floor(200000.0*$sin(cc*0.1296/per)+noise/1024.0+0.5);
		// $display("%d %d",cc,ind0);
		ind <= ind0;
	end
	ing <= (cc%per)<len;
end

wire signed [19:0] outd;
wire outg;
half_filt #(.len(len)) dut(.clk(clk), .reset(1'b0), .ind(ind), .ing(ing), .outd(outd), .outg(outg));

reg outg1=0;
always @(posedge clk) begin
	outg1 <= outg;
end

// always @(negedge clk) $display("%d %d %d %d", ind, ing, outd, outg);
always @(negedge clk) if (outg & ~outg1 & (cc>300)) $display("%d",outd);
endmodule

`timescale 1ns / 1ns
// Dual port memory with independent clocks, port B is read-only
// Altera and Xilinx synthesis tools successfully "find" this as block memory
module dpram #(
	parameter aw=8,
	parameter dw=8,
	parameter initial_file = ""
) (
	input clka,
	input clkb,
	input [aw-1:0] addra,
	output [dw-1:0] douta,
	input [dw-1:0] dina,
	input wena,
	input [aw-1:0] addrb,
	output [dw-1:0] doutb
);
localparam sz=32'b1<<aw;

reg [dw-1:0] mem[0:sz-1];
reg [aw-1:0] ala=0, alb=0;

// In principle the zeroing loop should work OK for synthesis, but
// there was a bug at least one version of Xilinx tools back in 2014.
// No known current tool needs it disabled.
integer k=0;
initial begin
	if (initial_file != "") $readmemh(initial_file, mem);
`ifndef BUGGY_FORLOOP
	else begin
		for (k=0;k<sz;k=k+1) mem[k]=0;
	end
`endif
end

assign douta = mem[ala];
assign doutb = mem[alb];
always @(posedge clka) begin
	ala <= addra;
	if (wena) mem[addra]<=dina;
end
always @(posedge clkb) begin
	alb <= addrb;
end

endmodule

